import{_ as t,o as s,c as a,a2 as e}from"./chunks/framework.Wufm-cgV.js";const c=JSON.parse('{"title":"多媒体支持","description":"通过 wr-proxy 处理音频、图片、视频内容","frontmatter":{"title":"多媒体支持","description":"通过 wr-proxy 处理音频、图片、视频内容"},"headers":[],"relativePath":"zh/guide/multimedia.md","filePath":"zh/guide/multimedia.md"}'),n={name:"zh/guide/multimedia.md"};function l(h,i,d,r,p,o){return s(),a("div",null,[...i[0]||(i[0]=[e(`<h1 id="多媒体支持" tabindex="-1">多媒体支持 <a class="header-anchor" href="#多媒体支持" aria-label="Permalink to &quot;多媒体支持&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>wr-proxy 为多媒体 API 端点提供一流支持 — 音频合成、语音转文字、图片生成和图片编辑 — 全部通过统一网关路由，具备自动故障切换和 Provider 选择能力。</p><h2 id="支持的端点" tabindex="-1">支持的端点 <a class="header-anchor" href="#支持的端点" aria-label="Permalink to &quot;支持的端点&quot;">​</a></h2><table tabindex="0"><thead><tr><th>端点</th><th>方法</th><th>内容类型</th><th>说明</th></tr></thead><tbody><tr><td><code>/v1/audio/speech</code></td><td>POST</td><td>JSON → 二进制音频</td><td>文字转语音合成</td></tr><tr><td><code>/v1/audio/transcriptions</code></td><td>POST</td><td>Multipart → JSON</td><td>语音转文字</td></tr><tr><td><code>/v1/images/generations</code></td><td>POST</td><td>JSON → JSON</td><td>图片生成（DALL·E 等）</td></tr><tr><td><code>/v1/images/edits</code></td><td>POST</td><td>Multipart → JSON</td><td>图片编辑</td></tr><tr><td><code>/v1/images/variations</code></td><td>POST</td><td>Multipart → JSON</td><td>图片变体</td></tr></tbody></table><h2 id="二进制内容处理方式" tabindex="-1">二进制内容处理方式 <a class="header-anchor" href="#二进制内容处理方式" aria-label="Permalink to &quot;二进制内容处理方式&quot;">​</a></h2><p>多媒体端点使用专用的快速通道（<code>handleBinaryProxy</code>），与标准聊天补全流程不同：</p><ol><li><strong>认证</strong> — 与聊天端点相同的 Token 认证</li><li><strong>模型提取</strong> — 从 JSON body 或 multipart 表单解析</li><li><strong>Provider 选择</strong> — 使用相同的健康感知路由器</li><li><strong>二进制透传</strong> — 响应体直接流式传输，不进行 JSON 解析</li></ol><h3 id="跳过的步骤" tabindex="-1">跳过的步骤 <a class="header-anchor" href="#跳过的步骤" aria-label="Permalink to &quot;跳过的步骤&quot;">​</a></h3><p>二进制代理有意跳过以下步骤（不适用于二进制内容）：</p><ul><li>复杂度评估（无文本可分析）</li><li>脱敏处理（音频/图片字节中无 PII）</li><li>请求清洗（格式因端点而异）</li><li>知识捕获（二进制内容不可捕获）</li></ul><h3 id="保留的能力" tabindex="-1">保留的能力 <a class="header-anchor" href="#保留的能力" aria-label="Permalink to &quot;保留的能力&quot;">​</a></h3><ul><li>Token 认证和模型白名单检查</li><li>Provider 健康感知选择与故障切换</li><li>冷却机制（额度耗尽、限流）</li><li>请求日志和成本计量</li><li>响应 Content-Type 透传</li></ul><h2 id="音频合成-tts" tabindex="-1">音频合成（TTS） <a class="header-anchor" href="#音频合成-tts" aria-label="Permalink to &quot;音频合成（TTS）&quot;">​</a></h2><p>将文字转为语音，可使用任意 Provider 提供的 TTS 模型。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:5051/v1/audio/speech</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Authorization: Bearer &lt;token&gt;&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Content-Type: application/json&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;{</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;model&quot;: &quot;tts-1&quot;,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;input&quot;: &quot;你好，欢迎使用 WebRouter！&quot;,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;voice&quot;: &quot;alloy&quot;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  }&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --output</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> speech.mp3</span></span></code></pre></div><h2 id="语音转文字-stt" tabindex="-1">语音转文字（STT） <a class="header-anchor" href="#语音转文字-stt" aria-label="Permalink to &quot;语音转文字（STT）&quot;">​</a></h2><p>将音频文件转为文字，支持 multipart 表单上传。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:5051/v1/audio/transcriptions</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Authorization: Bearer &lt;token&gt;&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -F</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;file=@recording.mp3&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -F</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;model=whisper-1&quot;</span></span></code></pre></div><h2 id="图片生成" tabindex="-1">图片生成 <a class="header-anchor" href="#图片生成" aria-label="Permalink to &quot;图片生成&quot;">​</a></h2><p>通过任意 OpenAI 兼容的 Provider 生成图片。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:5051/v1/images/generations</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Authorization: Bearer &lt;token&gt;&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Content-Type: application/json&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;{</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;model&quot;: &quot;dall-e-3&quot;,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;prompt&quot;: &quot;日落时分的宁静山湖&quot;,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;n&quot;: 1,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;size&quot;: &quot;1024x1024&quot;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  }&#39;</span></span></code></pre></div><h2 id="provider-兼容性" tabindex="-1">Provider 兼容性 <a class="header-anchor" href="#provider-兼容性" aria-label="Permalink to &quot;Provider 兼容性&quot;">​</a></h2><p>任何提供 OpenAI 兼容端点的 Provider 均支持：</p><table tabindex="0"><thead><tr><th>Provider</th><th>TTS</th><th>STT</th><th>图片生成</th></tr></thead><tbody><tr><td>OpenAI</td><td>tts-1, tts-1-hd</td><td>whisper-1</td><td>dall-e-3</td></tr><tr><td>Azure OpenAI</td><td>支持</td><td>支持</td><td>支持</td></tr><tr><td>自定义（OpenAI 兼容）</td><td>支持</td><td>支持</td><td>支持</td></tr></tbody></table><h2 id="故障切换行为" tabindex="-1">故障切换行为 <a class="header-anchor" href="#故障切换行为" aria-label="Permalink to &quot;故障切换行为&quot;">​</a></h2><p>多媒体请求遵循与聊天请求相同的故障切换逻辑：</p><ol><li>若所选 Provider 失败，wr-proxy 尝试下一个拥有相同模型的健康 Provider</li><li>被限流的 Provider 进入冷却（可配置时长）</li><li>额度耗尽的 Provider 冷却 30 分钟</li><li>通过 <code>max_failover</code> 和 <code>max_retry_count</code> 设置可配置</li></ol>`,28)])])}const u=t(n,[["render",l]]);export{c as __pageData,u as default};
